import React, { FC, useEffect, useState } from 'react';
import { classNames } from '../../helpers/classnames';
import { Button } from '../Button';
import { ColorPickerProps, IColorItem } from './ColorPicker.types';
import { standardColorPallet } from './constants';
import { isDarkColor } from './utils';

import './ColorPicker.scss';

export const ColorPicker: FC<ColorPickerProps> = ({ color = null, clearable = false, onChange }) => {
	const colors: IColorItem[] = [...standardColorPallet];
	const [internalColor, setInternalColor] = useState<string | null>(color);

	useEffect(() => {
		setInternalColor(color);
	}, [color]);

	const getColorItem = (color: string | null): IColorItem => {
		let colorItem = colors.find(findColor => findColor.hex && findColor.hex.toLowerCase() === color?.toLowerCase());
		if (!colorItem) {
			if (color) {
				colorItem = { hex: color, title: 'Пользовательский' } as IColorItem;
			} else {
				colorItem = { hex: '', title: 'Цвет не задан' } as IColorItem;
			}
		}
		return colorItem;
	};

	const equalsColor = (color1: string | null | undefined, color2: string | null | undefined): boolean => {
		if (!color1 || !color2) {
			return false;
		}
		return color1.toLowerCase() === color2.toLowerCase();
	};

	const handleColorChange = (selectedColor: IColorItem | null, event?: React.MouseEvent): void => {
		// Предотвращаем всплытие события, чтобы не мешать работе dropdown
		event?.stopPropagation();
		const newColor = selectedColor ? selectedColor.hex : null;
		setInternalColor(newColor);
		onChange?.(newColor);
	};

	// Добавляем пользовательский цвет в палитру если его нет
	useEffect(() => {
		if (internalColor && !colors.find(findColor => equalsColor(findColor.hex, internalColor))) {
			colors.push({ hex: internalColor, title: 'Пользовательский' } as IColorItem);
		}
	}, [internalColor, colors]);

	const renderColorGrid = () => (
		<div className="dsb_color-picker__grid">
			<div className="dsb_color-picker__grid-colors">
				{colors.map(colorItem => (
					<Button
						key={colorItem.hex}
						variant="plain"
						size="small"
						className={classNames('dsb_color-picker__color-block', {
							'dsb_color-picker__color-block--selected': equalsColor(colorItem.hex, internalColor),
						})}
						style={{ backgroundColor: colorItem.hex }}
						onClick={event => handleColorChange(colorItem, event)}
						title={`${colorItem.title}: ${colorItem.hex}`}
					>
						{equalsColor(colorItem.hex, internalColor) && (
							<div
								className="dsb_color-picker__color-block-indicator"
								style={{ backgroundColor: isDarkColor(colorItem.hex) ? '#FFFFFF' : '#000000' }}
							/>
						)}
					</Button>
				))}
			</div>
			{clearable && internalColor && (
				<Button
					variant="plain"
					size="small"
					fullWidth={true}
					onClick={event => handleColorChange(null, event)}
					className="dsb_color-picker__clear-button"
				>
					очистить выбор
				</Button>
			)}
		</div>
	);

	return (
		<div className="dsb_color-picker" data-testid="ColorPicker">
			{renderColorGrid()}
		</div>
	);
};
